function withdraw(address token, uint128 amount) external {
    if (token == address(0)) revert ZeroAddress();
    if (amount == 0) revert InvalidAmount();
    if (balances[msg.sender][token] < amount) revert InsufficientBalance();

    IERC20(token).safeTransfer(msg.sender, amount);  // EXTERNAL CALL FIRST
    balances[msg.sender][token] -= amount;             // STATE UPDATE AFTER
    totalDeposits[token] -= amount;                    // STATE UPDATE AFTER

    emit Withdrawn(msg.sender, token, amount);
}
